import React, { useState } from 'react';
import StartPage from './components/StartPage';
import QuizPage from './components/QuizPage';
import ResultPage from './components/ResultPage';

function App() {
  const [currentPage, setCurrentPage] = useState('start');
  const [quizId, setQuizId] = useState(null);
  const [teamInfo, setTeamInfo] = useState(null);
  const [result, setResult] = useState(null);

  const handleQuizStart = (id, info) => {
    setQuizId(id);
    setTeamInfo(info);
    setCurrentPage('quiz');
  };

  const handleQuizSubmit = (quizResult) => {
    setResult(quizResult);
    setCurrentPage('result');
  };

  const handleTimeout = () => {
    alert('Time is up! Your quiz will be submitted.');
  };

  return (
    <div>
      {currentPage === 'start' && (
        <StartPage onQuizStart={handleQuizStart} />
      )}

      {currentPage === 'quiz' && quizId && (
        <QuizPage
          quizId={quizId}
          teamInfo={teamInfo}
          onSubmit={handleQuizSubmit}
          onTimeout={handleTimeout}
        />
      )}

      {currentPage === 'result' && result && (
        <ResultPage result={result} teamInfo={teamInfo} />
      )}
    </div>
  );
}

export default App;
